// Get AI reply from Extract Reply node
const item = $items('Extract Reply')[0].json;
const aiReply = item.aiReply;

// Get context from Build LLM Messages1
const ctx = $items('Build LLM Messages')[0].json;

// Previous conversation context
let recent = ctx.prevRecent || [];
const userMsg = ctx.userMessage;

// Append new turn
recent.push({ role: 'user', content: userMsg });
recent.push({ role: 'assistant', content: aiReply });

// Keep only last 3
const newRecent = recent.slice(-3);
// Normalize summary: treat "null", null, undefined as null
const prevSummary = ctx.prevSummary;
const newSummary =
  prevSummary === null ||
  prevSummary === undefined ||
  prevSummary === 'null'
    ? null
    : prevSummary;

return {
  json: {
    phone: ctx.phone,
    summary: newSummary,
    recent_messages: newRecent,
    aiReply,
    prev_recent_len: (ctx.prevRecent || []).length
  }
};

