        "type": {
          "type": "string",
          "enum": ["register", "unregister", "none"],
          "description": "Action to perform: register for event, unregister from event, or none for chat only"
        },
        "event_id": {
          "type": ["integer", "null"],
          "description": "Event ID when registering/unregistering, null for chat"
        }
      },
      "required": ["type", "event_id"],
      "additionalProperties": false
    }
  },
  "required": ["reply_text","action"],
  "additionalProperties": false
}

