// We are directly after the Postgres node.
// So $json is the row returned by Load User & Chat.

const row = $json;

const phone        = row.phone;
const userText     = row.user_message;
const userName     = row.name;
const coordName    = row.coordinator_name;
const coordPhone   = row.coordinator_phone;

const prevSummary  = row.summary || null;
const prevRecent   = row.recent_messages || [];

const userContext = [];

// Add user name if available
if (userName) {
  userContext.push(`User: ${userName}`);
}

// Add conversation summary
if (prevSummary) {
  userContext.push(`Conversation Summary: ${prevSummary}`);
} else {
  userContext.push(`Status: First-time conversation`);
}

const contextString = userContext.join('\n');

// ============================================
// BUILD PROMPT STRING FOR AI NODE
// ============================================
let promptParts = [];

// Add context
promptParts.push(`CONTEXT:\n${contextString}\n`);

// Add recent conversation history
if (prevRecent && prevRecent.length > 0) {
  promptParts.push('RECENT CONVERSATION:');
  prevRecent.forEach(msg => {
    const role = msg.role.toUpperCase();
    promptParts.push(`${role}: ${msg.content}`);
  });
  promptParts.push('');  // Empty line before current message
}

// Add current user message
promptParts.push(`USER: ${userText}`);

const prompt = promptParts.join('\n');
return {
  json: {
    phone,
    userName,
    coordName,
    coordPhone,
    prevSummary,
    prevRecent,
    text: userText,
    prompt
  }
};

// Support both shapes:
// 1) { output: "{ \"reply_text\": ..., \"action\": {...} }" }
// 2) { reply_text: "...", action: {...} }

let outputObj;

// Case 1: wrapper with "output"
if ($json.output !== undefined) {
  const raw = $json.output;
  try {
    outputObj = typeof raw === 'string' ? JSON.parse(raw) : raw;
  } catch (e) {
    throw new Error('Could not parse JSON from AI output.output: ' + raw);
  }
} else {
  // Case 2: already structured
  outputObj = $json;
}

// Basic validation
if (!outputObj || typeof outputObj.reply_text !== 'string' || typeof outputObj.action !== 'object') {
  throw new Error('AI output missing reply_text or action fields: ' + JSON.stringify(outputObj));
}

return {
  json: {
    aiReply: outputObj.reply_text,
    action_type: outputObj.action.type || 'none',
    event_id: outputObj.action.event_id ?? null
  }
};

// Expecting request body like:
// { "phone": "+91...", "message": "text" }

// In webhook executions, n8n puts JSON under $json.body
// but in the full wrapper you also see it under $json.params.body.
// We'll support both to be safe.

const body = $json.body || ($json.params && $json.params.body) || $json;

const phone = body.phone;
const message = body.message;

if (!phone || !message) {
  throw new Error('Missing phone or message in request body');
}

return {
  json: {
    phone,
    message
  }
};

// Get the new summary from OpenAI response
const summaryText = $json.message?.content || $json.text || $json.choices?.[0]?.message?.content || '';

// Get the original context data from Update chat context node
const base = $items('Update chat context1')[0].json;

return {
  json: {
    phone: base.phone,
    summary: summaryText.trim(),
    // Keep only last 3 messages (1.5 turns) after rotation
    recent_messages: (base.recent_messages || []).slice(-3)
  }
};
